python3 -c "
import csv, json

# Get all active questions and their predictions
active_preds = {}
with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        if row['is_resolved'] == 'False':
            pred_str = row['my_prediction']
            if pred_str and pred_str != 'None':
                try:
                    pred = eval(pred_str)
                    active_preds[row['qid']] = pred
                except:
                    pass

# Get already submitted today
submitted = set()
try:
    with open('predictions/2026-02-13.json', 'r') as f:
        preds = json.load(f)
        for p in preds:
            submitted.add(p['question_id'])
except:
    pass

# Get remaining
remaining = {k:v for k,v in active_preds.items() if k not in submitted}
print(f'Need to submit {len(remaining)} predictions')

# Output as JSON for batch submission
with open('/tmp/remaining_preds.json', 'w') as f:
    json.dump(remaining, f)
print('Saved to /tmp/remaining_preds.json')
# Print first 5 for verification
for i, (qid, pred) in enumerate(list(remaining.items())[:5]):
    print(f'{qid}: {pred}')
"

